import {
  computed,
  Default,
  fetchBinary,
  type FetchBinaryResult,
  NAME,
  pattern,
  type Stream,
  UI,
  type VNode,
} from "commonfabric";

/** Notification sent when this instance's generation completes. */
export interface GeneratedArtEvent {
  /** The caller-supplied `id` input, passed back for correlation. */
  id: string;
  /** The generated image as a persistable `data:` URL. */
  imageUrl: string;
}

// Cuisine illustration thumbnail. Callers can disable generation and pass a
// stored source URL; a parent that owns item state can persist the returned
// image bytes for other viewers.
const GENERATE_IMAGE_PATH = "/api/ai/img";
const GENERATED_IMAGE_SIZE = 128;

export const FOOD_FALLBACK_IMAGE =
  "data:image/png;base64,";

// Art-director prompt. Goals (hard-won from early results): capture the
// *essence* of the cuisine like a minimal "parti diagram" rather than a busy
// scene, and draw the FOOD — inferring the cuisine from the restaurant name
// rather than illustrating the name literally (e.g. "…Palace of Indian
// Cuisine" should yield a dish, not a palace). Kept here so the style stays
// consistent across options and is easy to tune in one place.
const cuisineArtPrompt = (title: string) =>
  "A tiny 128x128 thumbnail intended to serialize to about 10 kB. " +
  "A hand-drawn pen-and-ink illustration with visible hand-inked pen strokes " +
  "and light crosshatching, as if sketched by hand with a fountain pen, with " +
  "gentle, restrained washes of soft watercolor color — present and warm but " +
  "understated, never saturated: a single close-up " +
  "of one iconic dish that captures the essence of a cuisine. The food fills " +
  "most of the frame, cropped at the edges to emphasize the food itself. A " +
  "plate or bowl is fine but not required — show the food however best suits " +
  "the dish (on a board, wrapped, or on its own). Infer the cuisine from " +
  "this restaurant's name " +
  `and draw only the food — "${title}". One dish only, not a pair. Do not ` +
  "draw buildings, palaces, storefronts, logos, people, or text. Clean white " +
  "background, no border.";

export const safeImageUrl = (raw: string | undefined): string => {
  const s = (raw ?? "").trim();
  if (!s) return "";
  if (s.startsWith("data:image/")) return s;
  try {
    const u = new URL(s);
    return (u.protocol === "http:" || u.protocol === "https:")
      ? u.toString()
      : "";
  } catch {
    return "";
  }
};

export const generatedImageUrlFor = (title: string): string =>
  GENERATE_IMAGE_PATH + "?prompt=" +
  encodeURIComponent(cuisineArtPrompt(title)) +
  "&width=" + GENERATED_IMAGE_SIZE +
  "&height=" + GENERATED_IMAGE_SIZE;

/**
 * GeneratedArt renders a fallback-backed food illustration thumbnail.
 *
 * Use it when a parent pattern needs fixed-size generated-or-stored image UI
 * from a text prompt. This sub-pattern owns no shared state; callers pass any
 * persisted source URL and decide whether this instance may generate.
 */

/**
 * Fetch lifecycle exposed by GeneratedArt for parents that need to observe or
 * persist generated image state.
 */
export type GeneratedArtFetchState =
  | "stored"
  | "generated"
  | "pending"
  | "error"
  | "requested"
  | "";

/**
 * Inputs for the generated thumbnail sub-pattern.
 *
 * Use JSX when embedding only the UI: `<GeneratedArt prompt={title} />`.
 * Instantiate with a function call when the parent needs `image` or
 * `fetchState`.
 */
export interface GeneratedArtInput {
  /** Text used to build the food-illustration art-director prompt. */
  prompt: string;

  /** Safe persisted image URL or data URI; when present, generation is skipped. */
  sourceUrl?: string | Default<"">;

  /** Whether this instance may call the image generation endpoint. */
  shouldGenerate?: boolean | Default<true>;

  /** Correlation id echoed in `onGenerated` events (e.g. the option id). */
  id?: string | Default<"">;

  /**
   * Parent-owned stream notified once with the generated image's data URL
   * (plus the `id` input). The idiomatic persistence seam: the parent's
   * handler stores the value and passes it back as `sourceUrl`, after which
   * this instance stops generating. The notify runs INSIDE this pattern on
   * purpose — computed outputs derived from fetch cells do not currently
   * materialize for parent readers (see the CT-1811-family runtime gap), so
   * parents must be told, not read.
   */
  onGenerated?: Stream<GeneratedArtEvent>;
}

/**
 * Outputs for the generated thumbnail sub-pattern.
 *
 * `[UI]` is a static VNode. The fallback image remains a static CSS
 * `background-image`; the generated (`cf-image`) or stored (`<img>`) overlay
 * shows only once real image data is available.
 */
export interface GeneratedArtOutput {
  /** Human-readable pattern name. */
  [NAME]: string;

  /** Static VNode rendering the fallback-backed square thumbnail. */
  [UI]: VNode;

  /**
   * Generated image bytes + media type once the fetch resolves; `undefined`
   * while only the fallback shows. A parent that owns item state can persist
   * these for other viewers.
   */
  image: FetchBinaryResult | undefined;

  /**
   * The generated image as a `data:` URL (`""` until generated). The
   * persistence-friendly form: a parent stores this string in shared state
   * (e.g. an option's `imageUrl`) and passes it back as `sourceUrl`, after
   * which every viewer serves the stored value and no instance generates.
   */
  imageDataUrl: string;

  /** Current image source/generation state. */
  fetchState: GeneratedArtFetchState;

  /**
   * `"sent"` once the `onGenerated` notification fired (`""` otherwise).
   * Drives the notify computed; NOT reliably readable by parents (fetch-cell
   * derived — the same CT-1811-family gap as `fetchState`).
   */
  notifyState: string;
}

export default pattern<GeneratedArtInput, GeneratedArtOutput>(
  ({ prompt, sourceUrl, shouldGenerate, id, onGenerated }) => {
    const requestUrl = computed(() => {
      // Guard the transiently-unset prompt (a map element materializing):
      // without it a real generation request goes out with "undefined"/"" in
      // the art prompt (CT-1820's adjacent hazard).
      const title = (prompt ?? "").trim();
      if (!title) return "";
      const stored = safeImageUrl(sourceUrl);
      if (stored) return "";
      if (shouldGenerate === false) return "";
      return generatedImageUrlFor(title);
    });

    const generatedArt = fetchBinary({
      url: requestUrl,
      options: {
        mutexTimeoutMs: 30_000,
      },
    });

    const image = computed(() => generatedArt.result);
    const imageBytes = computed(() => generatedArt.result?.bytes);
    const imageMediaType = computed(() => generatedArt.result?.mediaType ?? "");
    const imageDataUrl = computed(() => {
      const bytes = generatedArt.result?.bytes;
      const mediaType = generatedArt.result?.mediaType;
      if (!bytes || !mediaType) return "";
      // ~10 kB thumbnails; a simple char loop is fine at this size. `btoa` is
      // a hardened sandbox global; FabricBytes reads out via `slice()`.
      const raw = bytes.slice();
      let binary = "";
      for (let i = 0; i < raw.length; i++) {
        binary += String.fromCharCode(raw[i]);
      }
      return `data:${mediaType};base64,${btoa(binary)}`;
    });
    const hasSourceUrl = computed(() => safeImageUrl(sourceUrl) !== "");
    const hasGeneratedImage = computed(() => !!generatedArt.result?.bytes);
    const fetchState = computed(() => {
      if (!(prompt ?? "").trim()) return "";
      if (safeImageUrl(sourceUrl)) return "stored";
      if (shouldGenerate === false) return "";
      if (generatedArt.result?.bytes) return "generated";
      if (generatedArt.pending) return "pending";
      return generatedArt.error ? "error" : "requested";
    });

    // Notify the parent's persistence stream once the generation resolves
    // (pre-#4325 idiom, kept child-internal — same-level fetch-cell reads).
    // The parent's handler is idempotent on the stored value, and once it
    // writes `sourceUrl` back, `requestUrl` goes empty and this instance
    // stops generating — so re-runs converge instead of looping.
    const notifyState = computed(() => {
      if (!onGenerated) return "";
      const generated = imageDataUrl;
      if (!generated) return "";
      onGenerated.send({ id: (id ?? "").trim(), imageUrl: generated });
      return "sent";
    });

    return {
      [NAME]: "Generated lunch art",
      [UI]: (
        <div
          style={{
            width: "96px",
            height: "96px",
            flexShrink: 0,
            borderRadius: "8px",
            overflow: "hidden",
            backgroundColor: "#f9fafb",
            backgroundImage: `url("${FOOD_FALLBACK_IMAGE}")`,
            backgroundSize: "cover",
            backgroundPosition: "center",
            border: "1px solid #eee",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          {hasSourceUrl
            ? (
              <img
                src={sourceUrl}
                alt=""
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                }}
              />
            )
            : hasGeneratedImage
            ? (
              <cf-image
                bytes={imageBytes}
                mediaType={imageMediaType}
                alt=""
                style={{
                  width: "100%",
                  height: "100%",
                }}
              />
            )
            : null}
        </div>
      ),
      image,
      imageDataUrl,
      fetchState,
      notifyState,
    };
  },
);
